  1→import {
  2→  NavigationProp,
  3→  useFocusEffect,
  4→  useIsFocused,
  5→  useNavigation,
  6→} from '@react-navigation/native';
  7→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
  8→import React, {
  9→  FC,
 10→  useEffect,
 11→  useLayoutEffect,
 12→  useMemo,
 13→  useRef,
 14→  useState,
 15→} from 'react';
 16→import { Dimensions } from 'react-native';
 17→
 18→import { useScreenViewTracking } from '../../hooks/tracking';
 19→import type { RescuePayload } from '../../services';
 20→import { usePermission, usePoints, useRescue } from '../../services';
 21→
 22→import { PropsRootStack } from '../../routes/Models';
 23→import { rescueDescription } from '../Points/data';
 24→import { CashbackInvoiceItem, InvoiceCashbackProps } from './models';
 25→import InvoiceCashbackSummaryView from './view';
 26→
 27→const InvoiceCashbackSummary: FC<InvoiceCashbackProps> = ({ route }) => {
 28→  useScreenViewTracking({
 29→    route,
 30→    title: 'Cashback na fatura',
 31→  });
 32→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
 33→  const isFocused = useIsFocused();
 34→  const { height } = Dimensions.get('window');
 35→  const { hasRedeemed, markAsRedeemed } = usePermission();
 36→  const alreadyMarkedRef = useRef(false);
 37→  const [hasAttemptedRescue, setHasAttemptedRescue] = useState(false);
 38→
 39→  const { conversionFactor } = usePoints();
 40→  const {
 41→    isLoading: isRescueLoading,
 42→    isError: isRescueFailed,
 43→    responseStatus: rescueStatus,
 44→    rescueRequest,
 45→    reset: rescueClear,
 46→  } = useRescue();
 47→
 48→  useLayoutEffect(() => {
 49→    if (isFocused) {
 50→      setHasAttemptedRescue(false);
 51→      rescueClear();
 52→    }
 53→  }, [
 54→    isFocused,
 55→    rescueClear,
 56→  ]);
 57→
 58→  useFocusEffect(
 59→    React.useCallback(() => {
 60→      setHasAttemptedRescue(false);
 61→      rescueClear();
 62→      return undefined;
 63→    }, [rescueClear]),
 64→  );
 65→
 66→  const handleGoBack = () => {
 67→    setHasAttemptedRescue(false);
 68→    rescueClear();
 69→    navigation.goBack();
 70→  };
 71→
 72→  const invoiceList = (pts: number): CashbackInvoiceItem[] => {
 73→    const finalPrice = pts * conversionFactor;
 74→    const formattedPrice = new Intl.NumberFormat('pt-BR', {
 75→      style: 'currency',
 76→      currency: 'BRL',
 77→    }).format(finalPrice);
 78→
 79→    return [
 80→      {
 81→        type: 'default',
 82→        icon: 'icon-switch-vertical',
 83→        iconColor: 'BRAND_BASE_01',
 84→        iconColorShape: 'INTENSE_COLOR_01',
 85→        description: `Cada ${pts.toLocaleString(
 86→          'pt-br',
 87→        )} pontos valem ${formattedPrice} no cashback`,
 88→      },
 89→      {
 90→        type: 'default',
 91→        icon: 'icon-calendar',
 92→        iconColor: 'BRAND_BASE_01',
 93→        iconColorShape: 'INTENSE_COLOR_01',
 94→        description:
 95→          'Você define quanto cashback quer aplicar na sua fatura aberta',
 96→      },
 97→      {
 98→        type: 'default',
 99→        icon: 'icon-payment-invoice',
100→        iconColor: 'BRAND_BASE_01',
101→        iconColorShape: 'INTENSE_COLOR_01',
102→        description:
103→          'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
104→      },
105→      {
106→        type: 'default',
107→        icon: 'icon-clock',
108→        iconColor: 'BRAND_BASE_01',
109→        iconColorShape: 'INTENSE_COLOR_01',
110→        description: 'O cashback acontece em até 72h',
111→      },
112→    ];
113→  };
114→
115→  const pointsSelected = route?.params?.pointsSelected ?? 0;
116→  const reaisSelected = route?.params?.reaisSelected ?? 0;
117→  const productCode = route?.params?.productCode ?? '0';
118→  const campaingId = route?.params?.campaingId;
119→
120→  const onConfirmRescue = () => {
121→    setHasAttemptedRescue(true);
122→    const payload: RescuePayload = {
123→      value: reaisSelected,
124→      campaignId: campaingId,
125→      productCode: productCode,
126→      description: rescueDescription[productCode],
127→    };
128→    rescueRequest(payload);
129→  };
130→
131→  const onExitResult = () => {
132→    setHasAttemptedRescue(false);
133→    rescueClear();
134→    navigation.navigate('RewardProgram');
135→  };
136→
137→  const isRescueConcluded = !isRescueFailed && !!rescueStatus;
138→  const showResult =
139→    isFocused && hasAttemptedRescue && (isRescueConcluded || isRescueFailed);
140→
141→  const items: CashbackInvoiceItem[] = invoiceList(pointsSelected);
142→
143→  const modalizeRef1 = useRef<PropsModalizeRef>(
144→    null as unknown as PropsModalizeRef,
145→  );
146→
147→  const onOpenDefault = () => {
148→    modalizeRef1.current?.open?.();
149→  };
150→
151→  useEffect(() => {
152→    if (
153→      showResult &&
154→      isRescueConcluded &&
155→      !alreadyMarkedRef.current &&
156→      hasRedeemed !== true
157→    ) {
158→      alreadyMarkedRef.current = true;
159→      markAsRedeemed().catch(() => {});
160→    }
161→  }, [
162→    showResult,
163→    isRescueConcluded,
164→    hasRedeemed,
165→    markAsRedeemed,
166→  ]);
167→
168→  const nfPtBR = useMemo(() => new Intl.NumberFormat('pt-BR'), []);
169→  const getFormatPoints = React.useCallback(
170→    (n: number) => nfPtBR.format(Math.max(0, Math.floor(n || 0))),
171→    [nfPtBR],
172→  );
173→  const formatCurrencyBR = (n: number) =>
174→    new Intl.NumberFormat('pt-BR', {
175→      style: 'currency',
176→      currency: 'BRL',
177→    })
178→      .format(Number.isFinite(n) ? n : 0)
179→      .replace(/\s/g, '');
180→
181→  const formattedSelectedPoints = useMemo(
182→    () => getFormatPoints(pointsSelected || 0),
183→    [
184→      getFormatPoints,
185→      pointsSelected,
186→    ],
187→  );
188→
189→  const formattedSelectedReais = useMemo(
190→    () => formatCurrencyBR(reaisSelected || 0),
191→    [reaisSelected],
192→  );
193→
194→  const effectiveShowResult =
195→    typeof showResult !== 'undefined'
196→      ? showResult
197→      : !!(isRescueConcluded || isRescueFailed);
198→  const screenTitle = effectiveShowResult ? 'Conclusão' : 'Cashback na fatura';
199→
200→  return (
201→    <InvoiceCashbackSummaryView
202→      handleGoBack={handleGoBack}
203→      onConfirmRescue={onConfirmRescue}
204→      onExitResult={onExitResult}
205→      isRescueLoading={isRescueLoading}
206→      isRescueConcluded={isRescueConcluded}
207→      isRescueFailed={isRescueFailed}
208→      items={items}
209→      effectiveShowResult={showResult}
210→      onOpenDefault={onOpenDefault}
211→      modalizeRef1={modalizeRef1}
212→      formattedSelectedPoints={formattedSelectedPoints}
213→      formattedSelectedReais={formattedSelectedReais}
214→      screenTitle={screenTitle}
215→      height={height}
216→    />
217→  );
218→};
219→
220→export default InvoiceCashbackSummary;
221→

