11→  handleGoBack: () => void;
12→  handleContinue?: () => void;
13→  cashbackInvoiceList?: (pts: number, price: number) => CashbackInvoiceItem[];
14→  pts?: number;
15→  price?: number;
16→  pointsQuantity?: number;
17→  conversionFactor?: number;
18→  pointsSelected?: number;
19→  reaisSelected?: number;
20→  onConfirmRescue: () => void;
21→  onExitResult: () => void;
22→  isRescueLoading?: boolean;
23→  isRescueConcluded?: boolean;
24→  isRescueFailed?: boolean;
25→  showResult?: boolean;
26→  effectiveShowResult?: boolean;
27→  items: CashbackInvoiceItem[];
28→  modalizeRef1: React.RefObject<PropsModalizeRef>;
29→  onOpenDefault: () => void;
30→  formattedSelectedPoints: string;
31→  formattedSelectedReais: string;
