33→  height: number;
34→}
35→
36→export interface InvoiceCashbackProps extends NativeStackScreenProps<
37→  PropsFintechCardRoutes,
38→  'InvoiceCashbackSummary'
39→> {}
40→
41→export interface CashbackInvoiceItem {
42→  text?: string;
43→  type: TextIconType;
44→  icon: PropsIconsNameCore;
45→  iconColor: PropsTokenColorsCore;
46→  iconColorShape: PropsTokenColorsCore;
47→  description: string;
48→}
